<template><div class="panel"><div class="section-head"><div><h2>登录日志</h2><p>记录登录成功与失败事件。</p></div><el-button @click="load">刷新</el-button></div><el-table :data="rows"><el-table-column prop="loginAt" label="时间"/><el-table-column prop="username" label="账号"/><el-table-column prop="ipAddress" label="IP"/><el-table-column prop="userAgent" label="客户端" show-overflow-tooltip/><el-table-column label="结果"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="message" label="说明"/></el-table></div></template><script setup>import{onMounted,ref}from'vue';import http from'../api/http';const rows=ref([]);/** 加载登录日志。 */async function load(){rows.value=(await http.get('/system/login-logs')).data}onMounted(load)</script>
